var fullJustify = function(words, maxWidth) {
    const res = [];
    let line = [];
    let length = 0;
    for (const w of words) {
        if (length + line.length + w.length > maxWidth) {
            const spaces = maxWidth - length;
            if (line.length === 1) {
                res.push(line[0] + ' '.repeat(spaces));
            } else {
                const gaps = line.length - 1;
                const base = Math.floor(spaces / gaps), extra = spaces % gaps;
                let s = '';
                for (let idx = 0; idx < line.length; idx++) {
                    s += line[idx];
                    if (idx < gaps) s += ' '.repeat(base + (idx < extra ? 1 : 0));
                }
                res.push(s);
            }
            line = [];
            length = 0;
        }
        line.push(w);
        length += w.length;
    }
    let last = line.join(' ');
    last += ' '.repeat(maxWidth - last.length);
    res.push(last);
    return res;
};
